import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Save } from 'lucide-react';
import { getPresupuestoOnline, createPresupuestoOnline, updatePresupuestoOnline } from '../../services/api';
import Loading from '../common/Loading';

const FILAS_FIJAS = Array.from({ length: 11 }, () => ({ detalle: 'LONGITUD', es_unidad: false }));

const ESPECIALES = [
  { detalle: 'ZÓCALOS', es_unidad: false },
  { detalle: 'APERTURA + PEGADO PILETA', es_unidad: true },
  { detalle: 'APERTURA PILETA APOYO', es_unidad: true },
  { detalle: 'MENSULAS', es_unidad: true },
  { detalle: 'APERTURA ANAFE', es_unidad: true },
  { detalle: 'TERMINACIÓN', es_unidad: true },
  { detalle: 'PILETA MOD', es_unidad: true },
];

function emptyItem(detalle = 'LONGITUD', es_unidad = false) {
  return { detalle, largo: 0, ancho: 0, m2: 0, es_unidad, moneda: 'ARS', cantidad: 1, precio_unitario: 0, subtotal: 0 };
}

export default function PresupuestoOnlineForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEdit = !!id;
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);
  const [items, setItems] = useState(FILAS_FIJAS.map((f) => emptyItem(f.detalle, f.es_unidad)));
  const [especiales, setEspeciales] = useState(ESPECIALES.map((e) => emptyItem(e.detalle, e.es_unidad)));
  const [cliente, setCliente] = useState('');
  const [tipoObra, setTipoObra] = useState('');
  const [fecha, setFecha] = useState(new Date().toISOString().slice(0, 10));
  const [dolarDia, setDolarDia] = useState(1000);
  const [totalArs, setTotalArs] = useState(0);
  const [totalUsd, setTotalUsd] = useState(0);
  const [totalConsolidado, setTotalConsolidado] = useState(0);

  useEffect(() => {
    if (isEdit) {
      getPresupuestoOnline(id).then((res) => {
        const d = res.data;
        setCliente(d.cliente || '');
        setTipoObra(d.tipo_obra || '');
        setFecha(d.fecha || new Date().toISOString().slice(0, 10));
        setDolarDia(d.dolar_dia || 1000);
        if (d.items?.length) {
          const normales = d.items.filter((i) => !i.es_unidad);
          const esp = d.items.filter((i) => i.es_unidad);
          setItems(FILAS_FIJAS.map((f, idx) => normales[idx] || emptyItem(f.detalle, f.es_unidad)));
          setEspeciales(ESPECIALES.map((e, idx) => esp[idx] || emptyItem(e.detalle, e.es_unidad)));
        }
        setLoading(false);
      });
    }
  }, [id, isEdit]);

  const updateItem = (idx, field, value, isEspecial) => {
    const list = isEspecial ? [...especiales] : [...items];
    list[idx] = { ...list[idx], [field]: value };

    if (field === 'largo' || field === 'ancho') {
      const la = Number(list[idx].largo) || 0;
      const an = Number(list[idx].ancho) || 0;
      if (!list[idx].es_unidad) {
        list[idx].m2 = Math.round(la * an * 10000) / 10000;
      }
    }

    const m2 = list[idx].m2 || 0;
    const cant = Number(list[idx].cantidad) || 1;
    const pu = Number(list[idx].precio_unitario) || 0;
    if (list[idx].es_unidad) {
      list[idx].subtotal = Math.round(cant * pu * 100) / 100;
    } else if (m2 > 0) {
      list[idx].subtotal = Math.round(m2 * cant * pu * 100) / 100;
    } else {
      list[idx].subtotal = Math.round(cant * pu * 100) / 100;
    }

    if (isEspecial) setEspeciales(list);
    else setItems(list);
    recalcTotales();
  };

  const recalcTotales = () => {
    let ars = 0, usd = 0;
    const all = [...items, ...especiales];
    all.forEach((i) => {
      if (i.moneda === 'USD') usd += i.subtotal || 0;
      else ars += i.subtotal || 0;
    });
    setTotalArs(Math.round(ars * 100) / 100);
    setTotalUsd(Math.round(usd * 100) / 100);
    const dd = Number(dolarDia) || 1;
    setTotalConsolidado(Math.round((ars + usd * dd) * 100) / 100);
  };

  useEffect(() => { recalcTotales(); }, [dolarDia]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = {
        cliente, tipo_obra: tipoObra, fecha,
        dolar_dia: Number(dolarDia) || 1000,
        items: [...items, ...especiales],
        total_neto_ars: totalArs,
        total_neto_usd: totalUsd,
        total_consolidado: totalConsolidado,
      };
      if (isEdit) await updatePresupuestoOnline(id, payload);
      else await createPresupuestoOnline(payload);
      navigate('/presupuestos-online');
    } catch (err) { alert('Error al guardar'); }
    finally { setSaving(false); }
  };

  const generarWhatsApp = () => {
    const L = [];
    L.push('🏛️ AFAMAR - MÁRMOLES & GRANITOS');
    L.push('📍 LA PLATA, BS AS');
    if (cliente) L.push(`👤 Cliente: ${cliente}`);
    if (tipoObra) L.push(`🏗️ Obra: ${tipoObra}`);
    if (fecha) L.push(`📅 Fecha: ${fecha}`);
    L.push('');

    const all = [...items, ...especiales];
    const itemsUsd = all.filter((i) => i.subtotal > 0 && i.moneda === 'USD');
    const itemsArs = all.filter((i) => i.subtotal > 0 && i.moneda === 'ARS');

    if (itemsUsd.length) {
      L.push('💰 Cotizado en DÓLARES (USD):');
      L.push('');
      itemsUsd.forEach((i) => {
        let t = `• ${i.detalle}`;
        if (i.es_unidad) t += ` | Cant: ${i.cantidad}`;
        else if (i.m2 > 0) t += ` | ${i.largo}×${i.ancho} = ${i.m2.toFixed(4)} m²`;
        t += ` | USD ${i.precio_unitario.toFixed(2)}/u`;
        t += ` = USD ${i.subtotal.toLocaleString('es-AR', { minimumFractionDigits: 2 })}`;
        L.push(t);
      });
      L.push('');
    }

    if (itemsArs.length) {
      L.push('💵 Cotizado en PESOS (ARS):');
      L.push('');
      itemsArs.forEach((i) => {
        let t = `• ${i.detalle}`;
        if (i.es_unidad) t += ` | Cant: ${i.cantidad}`;
        else if (i.m2 > 0) t += ` | ${i.largo}×${i.ancho} = ${i.m2.toFixed(4)} m²`;
        t += ` | $ ${i.precio_unitario.toFixed(2)}/u`;
        t += ` = $ ${i.subtotal.toLocaleString('es-AR', { minimumFractionDigits: 2 })}`;
        L.push(t);
      });
      L.push('');
    }

    L.push('━━━━━━━━━━━━━━━━━━━━');
    if (totalUsd > 0) L.push(`💲 TOTAL USD: USD ${totalUsd.toLocaleString('es-AR', { minimumFractionDigits: 2 })}`);
    if (totalArs > 0) L.push(`💵 TOTAL ARS: $ ${totalArs.toLocaleString('es-AR', { minimumFractionDigits: 2 })}`);
    if (totalUsd > 0 && dolarDia > 0) {
      L.push(`📊 Dólar del día: $${Number(dolarDia).toLocaleString('es-AR')}`);
      L.push(`🔥 TOTAL CONSOLIDADO: $ ${totalConsolidado.toLocaleString('es-AR', { minimumFractionDigits: 2 })}`);
    }
    L.push('');
    L.push('📲 Consultas al WhatsApp');
    return L.join('\n');
  };

  const inputStyle = { width: '100%', padding: '4px 6px', border: '1px solid #d1d5db', borderRadius: 4, fontSize: 12, textAlign: 'right', boxSizing: 'border-box' };
  const inputTextStyle = { ...inputStyle, textAlign: 'left' };
  const selectStyle = { ...inputStyle, textAlign: 'center', cursor: 'pointer' };
  const cellStyle = { padding: '3px 4px' };

  if (loading) return <Loading />;

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
        <h1 style={{ fontSize: 22, fontWeight: 700 }}>
          {isEdit ? 'Editar Presupuesto en Línea' : 'Nuevo Presupuesto en Línea'}
        </h1>
      </div>

      <form onSubmit={handleSubmit}>
        {/* Encabezado */}
        <div className="card" style={{ marginBottom: 16 }}>
          <div style={{ fontSize: 14, fontWeight: 700, color: '#b91c1c', marginBottom: 12 }}>
            🏛️ AFAMAR - MÁRMOLES & GRANITOS — LA PLATA, BS AS
          </div>
          <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap', alignItems: 'flex-end' }}>
            <div className="form-group" style={{ flex: 1, minWidth: 180 }}>
              <label>CLIENTE / EMPRESA</label>
              <input className="input" value={cliente} onChange={(e) => setCliente(e.target.value)} placeholder="Nombre del cliente" />
            </div>
            <div className="form-group" style={{ flex: 1, minWidth: 180 }}>
              <label>TIPO DE OBRA</label>
              <input className="input" value={tipoObra} onChange={(e) => setTipoObra(e.target.value)} placeholder="Ej: Cocina, Baño" />
            </div>
            <div className="form-group" style={{ width: 140 }}>
              <label>FECHA</label>
              <input type="date" className="input" value={fecha} onChange={(e) => setFecha(e.target.value)} />
            </div>
            <div className="form-group" style={{ width: 160 }}>
              <label style={{ fontWeight: 700, color: '#1e40af' }}>DÓLAR DEL DÍA</label>
              <input type="number" step="1" className="input" style={{ fontWeight: 700, color: '#1e40af', borderColor: '#93c5fd', textAlign: 'center', fontSize: 16 }}
                value={dolarDia} onChange={(e) => setDolarDia(Number(e.target.value) || 1)} />
            </div>
          </div>
        </div>

        {/* Tabla */}
        <div className="card" style={{ marginBottom: 16, overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
            <thead>
              <tr style={{ background: '#f8fafc' }}>
                <th style={{ ...cellStyle, textAlign: 'left', width: '18%' }}>Sector / Modelo</th>
                <th style={{ ...cellStyle, textAlign: 'center', width: '8%' }}>Largo</th>
                <th style={{ ...cellStyle, textAlign: 'center', width: '8%' }}>Ancho</th>
                <th style={{ ...cellStyle, textAlign: 'center', width: '8%' }}>M²/U</th>
                <th style={{ ...cellStyle, textAlign: 'center', width: '7%' }}>Cant.</th>
                <th style={{ ...cellStyle, textAlign: 'center', width: '7%' }}>Moneda</th>
                <th style={{ ...cellStyle, textAlign: 'right', width: '12%' }}>Precio Unit.</th>
                <th style={{ ...cellStyle, textAlign: 'right', width: '12%' }}>Subtotal</th>
              </tr>
            </thead>
            <tbody>
              <tr style={{ background: '#e0f2fe' }}>
                <td colSpan={8} style={{ ...cellStyle, fontWeight: 700, fontSize: 12, color: '#0369a1' }}>
                  📐 PRODUCCIÓN ESTÁNDAR
                </td>
              </tr>
              {items.map((item, idx) => (
                <tr key={idx}>
                  <td style={cellStyle}>
                    <input style={inputTextStyle} value={item.detalle} onChange={(e) => updateItem(idx, 'detalle', e.target.value, false)} />
                  </td>
                  <td style={cellStyle}>
                    <input type="number" step="any" style={inputStyle} value={item.largo || ''} onChange={(e) => updateItem(idx, 'largo', e.target.value, false)} />
                  </td>
                  <td style={cellStyle}>
                    <input type="number" step="any" style={inputStyle} value={item.ancho || ''} onChange={(e) => updateItem(idx, 'ancho', e.target.value, false)} />
                  </td>
                  <td style={{ ...cellStyle, textAlign: 'center', fontWeight: 600 }}>
                    {item.m2 > 0 ? item.m2.toFixed(4) : '-'}
                  </td>
                  <td style={cellStyle}>
                    <input type="number" style={inputStyle} value={item.cantidad} onChange={(e) => updateItem(idx, 'cantidad', e.target.value, false)} min="1" />
                  </td>
                  <td style={cellStyle}>
                    <select style={selectStyle} value={item.moneda} onChange={(e) => updateItem(idx, 'moneda', e.target.value, false)}>
                      <option value="ARS">ARS</option>
                      <option value="USD">USD</option>
                    </select>
                  </td>
                  <td style={cellStyle}>
                    <input type="number" step="any" style={inputStyle} value={item.precio_unitario || ''} onChange={(e) => updateItem(idx, 'precio_unitario', e.target.value, false)} />
                  </td>
                  <td style={{ ...cellStyle, textAlign: 'right', fontWeight: 600, color: item.moneda === 'USD' ? '#059669' : '#1e293b' }}>
                    {item.moneda === 'USD' ? 'USD ' : '$ '}
                    {(item.subtotal || 0).toLocaleString('es-AR', { minimumFractionDigits: 2 })}
                  </td>
                </tr>
              ))}
              <tr style={{ background: '#fef3c7' }}>
                <td colSpan={8} style={{ ...cellStyle, fontWeight: 700, fontSize: 12, color: '#92400e' }}>
                  ✂️ CORTES Y ACCESORIOS
                </td>
              </tr>
              {especiales.map((item, idx) => (
                <tr key={idx}>
                  <td style={cellStyle}>
                    <input style={inputTextStyle} value={item.detalle} onChange={(e) => updateItem(idx, 'detalle', e.target.value, true)} />
                  </td>
                  <td style={cellStyle}>
                    {!item.es_unidad && (
                      <input type="number" step="any" style={inputStyle} value={item.largo || ''} onChange={(e) => updateItem(idx, 'largo', e.target.value, true)} />
                    )}
                  </td>
                  <td style={cellStyle}>
                    {!item.es_unidad ? (
                      <input type="number" step="any" style={inputStyle} value={item.ancho || ''} onChange={(e) => updateItem(idx, 'ancho', e.target.value, true)} placeholder="Altura" />
                    ) : null}
                  </td>
                  <td style={{ ...cellStyle, textAlign: 'center', fontWeight: 600, color: item.es_unidad ? '#b91c1c' : '#1e293b' }}>
                    {item.es_unidad ? 'U' : (item.m2 > 0 ? item.m2.toFixed(4) : '-')}
                  </td>
                  <td style={cellStyle}>
                    <input type="number" style={inputStyle} value={item.cantidad} onChange={(e) => updateItem(idx, 'cantidad', e.target.value, true)} min="1" />
                  </td>
                  <td style={cellStyle}>
                    <select style={selectStyle} value={item.moneda} onChange={(e) => updateItem(idx, 'moneda', e.target.value, true)}>
                      <option value="ARS">ARS</option>
                      <option value="USD">USD</option>
                    </select>
                  </td>
                  <td style={cellStyle}>
                    <input type="number" step="any" style={inputStyle} value={item.precio_unitario || ''} onChange={(e) => updateItem(idx, 'precio_unitario', e.target.value, true)} />
                  </td>
                  <td style={{ ...cellStyle, textAlign: 'right', fontWeight: 600, color: item.moneda === 'USD' ? '#059669' : '#1e293b' }}>
                    {item.moneda === 'USD' ? 'USD ' : '$ '}
                    {(item.subtotal || 0).toLocaleString('es-AR', { minimumFractionDigits: 2 })}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Totales */}
        <div className="card" style={{ marginBottom: 16 }}>
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 24, alignItems: 'center', flexWrap: 'wrap' }}>
            <div style={{ textAlign: 'right' }}>
              <div style={{ fontSize: 13, color: '#64748b' }}>TOTAL NETO ARS</div>
              <div style={{ fontSize: 20, fontWeight: 700, color: '#1e293b' }}>
                $ {totalArs.toLocaleString('es-AR', { minimumFractionDigits: 2 })}
              </div>
            </div>
            <div style={{ textAlign: 'right' }}>
              <div style={{ fontSize: 13, color: '#64748b' }}>TOTAL NETO USD</div>
              <div style={{ fontSize: 20, fontWeight: 700, color: '#059669' }}>
                USD {totalUsd.toLocaleString('es-AR', { minimumFractionDigits: 2 })}
              </div>
            </div>
            <div style={{ textAlign: 'right', background: '#dc2626', color: 'white', padding: '10px 24px', borderRadius: 8 }}>
              <div style={{ fontSize: 12, fontWeight: 600 }}>TOTAL CONSOLIDADO</div>
              <div style={{ fontSize: 14, fontWeight: 400, opacity: 0.8 }}>
                (ARS + USD × ${Number(dolarDia).toLocaleString('es-AR')})
              </div>
              <div style={{ fontSize: 22, fontWeight: 800 }}>$ {totalConsolidado.toLocaleString('es-AR', { minimumFractionDigits: 2 })}</div>
            </div>
          </div>
        </div>

        {/* Botones */}
        <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end', flexWrap: 'wrap' }}>
          <button type="button" className="btn btn-success" onClick={() => { navigator.clipboard.writeText(generarWhatsApp()); alert('¡Copiado! Pegalo en WhatsApp.'); }}
            style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"/></svg>
            Exportar para WhatsApp
          </button>
          <button type="button" className="btn btn-outline" onClick={() => navigate('/presupuestos-online')}>Cancelar</button>
          <button type="submit" className="btn btn-primary" disabled={saving} style={{ background: '#b91c1c' }}>
            <Save size={16} /> {saving ? 'GUARDANDO...' : 'GUARDAR'}
          </button>
        </div>
      </form>
    </div>
  );
}
